from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found: {index_path}") from e

    passage_manager: PassageManager = searcher.passage_manager
    total_passages = len(passage_manager.offset_map)

    # Collect metadata fields from all passages
    metadata_fields = set()
    field_values = defaultdict(list)

    for passage_id in passage_manager.offset_map.keys():
        passage_data = passage_manager.get_passage(passage_id)
        metadata = passage_data.get("metadata", {})

        # Collect field names
        for field_name in metadata.keys():
            metadata_fields.add(field_name)

        # Collect field values for counting
        for field_name, value in metadata.items():
            field_values[field_name].append(value)

    # Calculate value counts for each field
    field_value_counts = {}
    for field_name, values in field_values.items():
        field_value_counts[field_name] = dict(Counter(values))

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(list(metadata_fields)),
        "field_value_counts": field_value_counts
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found: {index_path}") from e

    passage_manager: PassageManager = searcher.passage_manager
    total_passages = len(passage_manager.offset_map)

    if total_passages == 0:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {},
            "missing_fields": required_fields.copy()
        }

    # Check which required fields are present in any passage
    present_fields = set()
    field_counts = defaultdict(int)

    for passage_id in passage_manager.offset_map.keys():
        passage_data = passage_manager.get_passage(passage_id)
        metadata = passage_data.get("metadata", {})

        # Check which required fields are present in this passage
        for field_name in required_fields:
            if field_name in metadata:
                present_fields.add(field_name)
                field_counts[field_name] += 1

    # Calculate coverage metrics
    missing_fields = [field for field in required_fields if field not in present_fields]

    # Calculate coverage percentage for all required fields
    passages_with_all_fields = 0
    for passage_id in passage_manager.offset_map.keys():
        passage_data = passage_manager.get_passage(passage_id)
        metadata = passage_data.get("metadata", {})

        # Check if all required fields are present in this passage
        all_fields_present = True
        for field_name in required_fields:
            if field_name not in metadata:
                all_fields_present = False
                break

        if all_fields_present:
            passages_with_all_fields += 1

    coverage_percentage = (passages_with_all_fields / total_passages) * 100

    # Calculate individual field coverage percentages
    field_coverage = {}
    for field_name in required_fields:
        if field_name in present_fields:
            field_coverage[field_name] = (field_counts[field_name] / total_passages) * 100
        else:
            field_coverage[field_name] = 0.0

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": field_coverage,
        "missing_fields": missing_fields
    }
